using Microsoft.AspNetCore.Authentication;
using System.IdentityModel.Tokens.Jwt;

public class JwtAuthMiddleware : AuthenticationMiddleware<IAuthenticationHandler>
{
    public JwtAuthMiddleware(RequestDelegate next, IOptions<AuthenticationOptions> options)
        : base(next, options)
    {
    }

    protected override async Task<AuthenticateResult> HandleAuthenticateAsync()
    {
        var authHeader = Request.Headers["Authorization"];
        if (authHeader.Count == 0 || !authHeader[0].StartsWith("Bearer ", StringComparison.OrdinalIgnoreCase))
        {
            return AuthenticateResult.NoResult();
        }

        var token = authHeader[0].Substring("Bearer ".Length);
        var jwtSecurityTokenHandler = new JwtSecurityTokenHandler();
        try
        {
            var jwtToken = jwtSecurityTokenHandler.ReadJwtToken(token);
            if (!jwtSecurityTokenHandler.ValidateToken(jwtToken))
            {
                return AuthenticateResult.Fail("Invalid signature");
            }

            var user = new ClaimsPrincipal(new ClaimsIdentity(jwtToken.Claims, "JWT"));
            Context.User = user;
            return AuthenticateResult.Success();
        }
        catch (Exception ex)
        {
            return AuthenticateResult.Fail("Error validating JWT token: " + ex.Message);
        }
    }
}